    auto N = x.size(0);
    auto Co = weight.size(0);
    auto Hi = x.size(2);
    auto Wi = x.size(3);
    auto Kh = weight.size(2);
    auto Kw = weight.size(3);
    auto Ho = Hi - Kh + 1;
    auto Wo = Wi - Kw + 1;
    at::Tensor y = at::empty({N, Co, Ho, Wo}, x.options());
    EXEC_NPU_CMD(aclnnConvStandard2dSquareInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

